1	export type Cell = [x: number, y: number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [0, -1], [1, -1],
5	  [-1,  0],          [1,  0],
6	  [-1,  1], [0,  1], [1,  1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const survives = (neighborCount: number, wasAlive: boolean): boolean =>
12	  neighborCount === 3 || (neighborCount === 2 && wasAlive);
13	
14	const neighborsOf = ([x, y]: Cell): Cell[] =>
15	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
16	
17	type NeighborTally = { cell: Cell; count: number };
18	
19	const tallyNeighbors = (livingCells: Cell[]): Map<string, NeighborTally> => {
20	  const tallies = new Map<string, NeighborTally>();
21	  for (const livingCell of livingCells) {
22	    for (const neighbor of neighborsOf(livingCell)) {
23	      const key = cellKey(neighbor);
24	      const tally = tallies.get(key) ?? { cell: neighbor, count: 0 };
25	      tally.count += 1;
26	      tallies.set(key, tally);
27	    }
28	  }
29	  return tallies;
30	};
31	
32	export function nextGeneration(livingCells: Cell[]): Cell[] {
33	  const aliveKeys = new Set(livingCells.map(cellKey));
34	  const tallies = tallyNeighbors(livingCells);
35	  return Array.from(tallies)
36	    .filter(([key, { count }]) => survives(count, aliveKeys.has(key)))
37	    .map(([, { cell }]) => cell);
38	}
