4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — [] → []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single cell dies (underpopulation) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent cells both die (underpopulation, each has 1 neighbor) — [(0,1), (1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("live cell with 4 neighbors dies (overpopulation) — center (1,1) excluded next gen", () => {
15	    const input: Cell[] = [
16	      [0, 0], [1, 0], [2, 0],
17	      [0, 1], [1, 1], [2, 1],
18	      [0, 2],         [2, 2],
19	    ];
20	    const result = nextGeneration(input);
21	    const resultSet = new Set(result.map((c) => c.join(",")));
22	    expect(resultSet.has("1,1")).toBe(false);
23	  });
24	  it("dead cell with exactly 3 neighbors becomes alive (reproduction) — L-shape [(0,2),(1,2),(0,1)] produces (1,1) alive", () => {
25	    const result = nextGeneration([[0, 2], [1, 2], [0, 1]]);
26	    const resultSet = new Set(result.map((c) => c.join(",")));
27	    expect(resultSet.has("1,1")).toBe(true);
28	  });
29	  it("live cell with 2 neighbors survives — center of horizontal triple stays alive", () => {
30	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
31	    const resultSet = new Set(result.map((c) => c.join(",")));
32	    expect(resultSet.has("1,0")).toBe(true);
33	  });
34	  it("block still life is unchanged — [(0,0),(1,0),(0,1),(1,1)] → same set", () => {
35	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
36	    const result = nextGeneration(block);
37	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
38	      new Set(block.map((c) => c.join(","))),
39	    );
40	  });
41	  it("blinker oscillates vertical to horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
42	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
43	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
44	      new Set(["-1,1", "0,1", "1,1"]),
45	    );
46	  });
47	  it("handles negative coordinates — vertical blinker at (-5,-5..-3) → horizontal at (-6..-4,-4)", () => {
48	    const result = nextGeneration([[-5, -5], [-5, -4], [-5, -3]]);
49	    expect(new Set(result.map((c) => c.join(",")))).toEqual(
50	      new Set(["-6,-4", "-5,-4", "-4,-4"]),
51	    );
52	  });
53	});
