export function nextGeneration(livingCells: Cell[]): Cell[] {
  const aliveKeys = new Set(livingCells.map(cellKey));
  const tallies = tallyNeighbors(livingCells);
  return Array.from(tallies)
    .filter(([key, { count }]) => survives(count, aliveKeys.has(key)))
    .map(([, { cell }]) => cell);
}

