export function nextGeneration(livingCells: Cell[]): Cell[] {
  const aliveKeys = new Set(livingCells.map(cellKey));
  const survivors: Cell[] = [];
  for (const [key, { cell, count }] of tallyNeighbors(livingCells)) {
    if (survives(count, aliveKeys.has(key))) survivors.push(cell);
  }
  return survivors;
}

